"""CLI for the task tracker."""

import sys
import os

# Ensure we can import from the same directory
sys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))

from eval37_storage import TaskStorage
from eval37_models import VALID_STATUSES, VALID_PRIORITIES


def print_task(task):
    status_icons = {"todo": "[ ]", "in_progress": "[~]", "done": "[✓]", "cancelled": "[✗]"}
    icon = status_icons.get(task.status, "[?]")
    print(f"  {icon} #{task.id} [{task.priority}] {task.title}")
    if task.description:
        print(f"      {task.description}")


def main():
    # BUG: hardcoded path instead of using temp/configurable path
    storage = TaskStorage("tmp/eval37_tasks.json")

    if len(sys.argv) < 2:
        print("Usage: python eval37_main.py <command> [args]")
        print("Commands: add, list, complete, delete, stats")
        return

    cmd = sys.argv[1]

    if cmd == "add":
        if len(sys.argv) < 3:
            print("Usage: add <title> [--priority low|medium|high|critical] [--desc description]")
            return
        title = sys.argv[2]
        priority = "medium"
        description = ""
        i = 3
        while i < len(sys.argv):
            if sys.argv[i] == "--priority" and i + 1 < len(sys.argv):
                priority = sys.argv[i + 1]
                i += 2
            elif sys.argv[i] == "--desc" and i + 1 < len(sys.argv):
                description = sys.argv[i + 1]
                i += 2
            else:
                i += 1
        task = storage.add(title, priority=priority, description=description)
        print(f"Added task #{task.id}: {task.title}")

    elif cmd == "list":
        status = None
        priority = None
        i = 2
        while i < len(sys.argv):
            if sys.argv[i] == "--status" and i + 1 < len(sys.argv):
                status = sys.argv[i + 1]
                i += 2
            elif sys.argv[i] == "--priority" and i + 1 < len(sys.argv):
                priority = sys.argv[i + 1]
                i += 2
            else:
                i += 1
        tasks = storage.list_tasks(status=status, priority=priority)
        if not tasks:
            print("No tasks found.")
        else:
            print(f"Tasks ({len(tasks)}):")
            for t in tasks:
                print_task(t)

    elif cmd == "complete":
        if len(sys.argv) < 3:
            print("Usage: complete <task_id>")
            return
        task_id = int(sys.argv[2])
        if storage.complete_task(task_id):
            print(f"Task #{task_id} completed.")
        else:
            print(f"Task #{task_id} not found.")

    elif cmd == "delete":
        if len(sys.argv) < 3:
            print("Usage: delete <task_id>")
            return
        task_id = int(sys.argv[2])
        if storage.delete_task(task_id):
            print(f"Task #{task_id} deleted.")
        else:
            print(f"Task #{task_id} not found.")

    elif cmd == "stats":
        # TODO: Implement statistics command
        # Should show: total tasks, count per status, count per priority
        print("Statistics command not yet implemented.")

    else:
        print(f"Unknown command: {cmd}")


if __name__ == "__main__":
    main()

